function twoSumSorted(nums: number[], target: number): [number, number] {
  let left: number = 0;
  let right: number = nums.length - 1;
  while (left < right) {
    const sum: number = nums[left] + nums[right];
    if (sum === target) return [left, right];
    if (sum < target) left++;
    else right--;
  }
  return [-1, -1];
}

console.log(twoSumSorted([1, 3, 5, 7, 10], 8));  // [0, 4]

